// Client uses explicitly provided member values over defaults
TEST(RestJsonRequestTest, RestJsonClientUsesExplicitlyProvidedMemberValuesOverDefaults) {
  Fixture fixture = MakeFixture();
  const OperationWithDefaultsInput input = [] {
  OperationWithDefaultsInput v{};
  v.defaults = [] {
  Defaults v{};
  v.defaultString = "bye";
  v.defaultBoolean = true;
  v.defaultList = std::vector<std::string>{"a"};
  v.defaultDocumentMap = [] {
  smithy::DocumentMap map;
  map.emplace("name", smithy::Document(std::string("Jack")));
  return smithy::Document(std::move(map));
}();
  v.defaultDocumentString = smithy::Document(std::string("bye"));
  v.defaultDocumentBoolean = smithy::Document(true);
  v.defaultDocumentList = [] {
  smithy::DocumentList list;
  list.emplace_back(smithy::Document(std::string("b")));
  return smithy::Document(std::move(list));
}();
  v.defaultNullDocument = smithy::Document(std::string("notNull"));
  v.defaultTimestamp = smithy::Timestamp::FromEpochMilliseconds(1000LL);
  v.defaultBlob = smithy::Blob::FromString("hi");
  v.defaultByte = 2;
  v.defaultShort = 2;
  v.defaultInteger = 20;
  v.defaultLong = 200LL;
  v.defaultFloat = 2.0F;
  v.defaultDouble = 2.0;
  v.defaultMap = std::map<std::string, std::string>{{"name", "Jack"}};
  v.defaultEnum = TestEnum::FromString("BAR");
  v.defaultIntEnum = static_cast<TestIntEnum>(2);
  v.emptyString = "foo";
  v.falseBoolean = true;
  v.emptyBlob = smithy::Blob::FromString("hi");
  v.zeroByte = 1;
  v.zeroShort = 1;
  v.zeroInteger = 1;
  v.zeroLong = 1LL;
  v.zeroFloat = 1.0F;
  v.zeroDouble = 1.0;
  return v;
}();
  return v;
}();
  (void)fixture.client.OperationWithDefaults(input);
  const smithy::http::HttpRequest& request = fixture.transport->last_request;
  EXPECT_EQ(request.method, "POST");
  EXPECT_EQ(smithy::testing::UriPath(request.target), "/OperationWithDefaults");
  EXPECT_EQ(request.headers.Get("Content-Type").value_or("<missing>"), "application/json");
  EXPECT_TRUE(smithy::testing::JsonBodyEquals("{\n    \"defaults\": {\n        \"defaultString\": \"bye\",\n        \"defaultBoolean\": true,\n        \"defaultList\": [\"a\"],\n        \"defaultDocumentMap\": {\"name\": \"Jack\"},\n        \"defaultDocumentString\": \"bye\",\n        \"defaultDocumentBoolean\": true,\n        \"defaultDocumentList\": [\"b\"],\n        \"defaultNullDocument\": \"notNull\",\n        \"defaultTimestamp\": 1,\n        \"defaultBlob\": \"aGk=\",\n        \"defaultByte\": 2,\n        \"defaultShort\": 2,\n        \"defaultInteger\": 20,\n        \"defaultLong\": 200,\n        \"defaultFloat\": 2.0,\n        \"defaultDouble\": 2.0,\n        \"defaultMap\": {\"name\": \"Jack\"},\n        \"defaultEnum\": \"BAR\",\n        \"defaultIntEnum\": 2,\n        \"emptyString\": \"foo\",\n        \"falseBoolean\": true,\n        \"emptyBlob\": \"aGk=\",\n        \"zeroByte\": 1,\n        \"zeroShort\": 1,\n        \"zeroInteger\": 1,\n        \"zeroLong\": 1,\n        \"zeroFloat\": 1.0,\n        \"zeroDouble\": 1.0\n    }\n}", request.body));
}

