// Uses the given idempotency token as-is
TEST(RestJsonRequestTest, RestJsonQueryIdempotencyTokenAutoFillIsSet) {
  Fixture fixture = MakeFixture();
  const QueryIdempotencyTokenAutoFillInput input = [] {
  QueryIdempotencyTokenAutoFillInput v{};
  v.token = "00000000-0000-4000-8000-000000000000";
  return v;
}();
  (void)fixture.client.QueryIdempotencyTokenAutoFill(input);
  const smithy::http::HttpRequest& request = fixture.transport->last_request;
  EXPECT_EQ(request.method, "POST");
  EXPECT_EQ(smithy::testing::UriPath(request.target), "/QueryIdempotencyTokenAutoFill");
  EXPECT_TRUE(smithy::testing::QueryContains(request.target, {"token=00000000-0000-4000-8000-000000000000"}));
  EXPECT_TRUE(request.body.empty()) << request.body;
}

